  function getActivePdfBuilder() {
    if (formData._formType === 'telephone') return buildTelephonePdfHtml;
    if (formData.attendanceMode === 'voluntary') return buildVoluntaryPdfHtml;
    return buildPdfHtml;
  }

  function getPdfBuilderForData(data) {
    if (data._formType === 'telephone') return buildTelephonePdfHtml;
    if (data.attendanceMode === 'voluntary') return buildVoluntaryPdfHtml;
    return buildPdfHtml;
  }
  window.getActivePdfBuilder = getActivePdfBuilder;
  window.getPdfBuilderForData = getPdfBuilderForData;
  window.buildPdfHtml = buildPdfHtml;
  window.buildVoluntaryPdfHtml = buildVoluntaryPdfHtml;
  window.buildTelephonePdfHtml = buildTelephonePdfHtml;
  // Exposed so the in-app LAA declaration block can be asserted at runtime
  // (mirrors window.buildPdfHtml for the PDF surface).
  window.buildLaaDeclarationFormHtmlForUi = buildLaaDeclarationFormHtmlForUi;

  var CONFIDENTIALITY_REMINDER = 'Only share with authorised recipients. Client confidentiality and SRA standards apply.';

  function confirmConfidentialityThen(action) {
    showConfirm(CONFIDENTIALITY_REMINDER + '\n\nContinue?', 'Confidentiality').then(function(ok) {
      if (ok && typeof action === 'function') action();
    });
  }

  function ensureAllSectionsRendered() {
    if (_formEnsureSectionRendered) {
      activeFormSections.forEach(function(_, i) { _formEnsureSectionRendered(i); });
    }
  }

  function exportPdf() {
    ensureAllSectionsRendered();
    ensureBillingDisplayInvoiceNumber({ skipSave: false });
    const data = getFormData();
    window.api.getSettings().then(settings => {
      const builder = getActivePdfBuilder();
      const html = builder(data, settings);
      const label = data._formType === 'telephone' ? 'tel-advice' : (data.attendanceMode === 'voluntary' ? 'voluntary' : 'attendance');
      const n = [data.surname, data.forename].filter(Boolean).join('_') || label;
      const fn = n + '-' + (data.ufn ? data.ufn.replace('/', '-') : '') + '-' + ((data.date || '').replace(/-/g, '') || Date.now()) + '.pdf';
      window.api.printToPdf({ html: html, filename: fn }).then(function(p) {
        showToast('PDF saved: ' + p, 'success');
      }).catch(e => showToast('PDF failed: ' + (e && e.message), 'error'));
    }).catch(function(e) { showToast('Export failed: could not load settings', 'error'); console.error('[exportPdf]', e); });
  }

  function exportDocx() {
    ensureAllSectionsRendered();
    var data = getFormData();
    window.api.getSettings().then(function(settings) {
      var label = data._formType === 'telephone' ? 'tel-advice' : (data.attendanceMode === 'voluntary' ? 'voluntary' : 'attendance');
      var n = [data.surname, data.forename].filter(Boolean).join('_') || label;
      var fn = n + '-' + (data.ufn ? data.ufn.replace('/', '-') : '') + '-' + ((data.date || '').replace(/-/g, '') || Date.now()) + '.docx';
      window.api.exportDocx({ data: data, settings: settings, filename: fn }).then(function(p) {
        showToast('Word document saved: ' + (p || '').replace(/\\/g, '/').split('/').pop(), 'success');
      }).catch(function(e) { showToast('Word export failed: ' + (e && e.message), 'error'); });
    }).catch(function(e) { showToast('Export failed: could not load settings', 'error'); console.error('[exportDocx]', e); });
  }

  /* Export PDF directly from a record ID (e.g. programmatic use).
     Opens the OS print/preview dialog so the user can print or save as PDF. */
  window.exportPdfById = function(recordId) {
    window.api.attendanceGet(recordId).then(function(row) {
      if (!row) { showToast('Record not found', 'error'); return; }
      var data = {};
      try {
        data = typeof row.data === 'string' ? JSON.parse(row.data) : (row.data || {});
      } catch (parseErr) {
        console.error('[exportPdfById] failed to parse record data', recordId, parseErr);
        showToast('Cannot generate PDF \u2014 record data is corrupt. Please open the record and re-save before exporting.', 'error');
        return;
      }
      ensureBillingDisplayInvoiceNumber({ data: data, skipSave: true });
      window.api.getSettings().then(function(settings) {
        var builder = getPdfBuilderForData(data);
        var html = builder(data, settings);
        printGeneratedDoc(html);
      });
    }).catch(function() { showToast('Could not load record', 'error'); });
  };

  function printAttendanceNote() {
    ensureAllSectionsRendered();
    const data = getFormData();
    window.api.getSettings().then(settings => {
      const builder = getActivePdfBuilder();
      const html = builder(data, settings);
      printGeneratedDoc(html);
    });
  }

  function exportBillingSummaryPdf() {
    ensureAllSectionsRendered();
    var d = getFormData();
    var html = buildBillingSummaryHtml(d);
    var n = [d.surname, d.forename].filter(Boolean).join('_') || 'billing';
    var fn = 'billing-summary-' + n + '-' + ((d.date || '').replace(/-/g, '') || Date.now()) + '.pdf';
    window.api.printToPdf({ html: html, filename: fn }).then(function(p) {
      showToast('Billing summary PDF saved: ' + p, 'success');
    }).catch(function(e) { showToast('PDF failed: ' + (e && e.message), 'error'); });
  }
  window.exportBillingSummaryPdf = exportBillingSummaryPdf;

  function buildBillingSummaryHtml(d) {
    d = d || {};
    var totals = (typeof resolveWorkflowBillingTotals === 'function') ? resolveWorkflowBillingTotals() : null;
    if (!totals && typeof calculateInvoiceTotals === 'function') {
      totals = calculateInvoiceTotals({ fixedFee: 0, mileageMiles: 0, mileageRate: 0.45, parkingAmount: 0, vatRate: 0.2 });
    }
    if (!totals) {
      totals = { fixedFee: 0, mileageAmount: 0, parkingAmount: 0, subTotal: 0, vatTotal: 0, grandTotal: 0, vatRate: 0.2, mileageMiles: 0, mileageRate: 0.45 };
    }
    function fc(v) { return '\u00A3' + (v || 0).toFixed(2); }
    // Attribute-safe HTML escape (was previously text-only — escaping " and '
    // is required if any caller uses esc() inside an attribute context;
    // currently this scope only emits text-context but the wider escape
    // is safer if call sites change).
    function esc(s) { return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;'); }
    function fmtDate(v) { if (!v) return ''; var m = String(v).match(/^(\d{4})-(\d{2})-(\d{2})/); return m ? m[3] + '/' + m[2] + '/' + m[1] : v; }
    var vatPct = (totals.vatRate != null) ? (Math.round(totals.vatRate * 1000) / 10) : 20;
    if (Math.abs(vatPct - Math.round(vatPct)) < 0.01) vatPct = Math.round(vatPct);
    var line1 = (typeof buildLine1Description === 'function')
      ? buildLine1Description({
          clientName: [d.forename, d.surname].filter(Boolean).join(' '),
          policeStation: d.policeStationName,
          attendanceDate: d.date,
        })
      : 'Police station attendance';
    var statusLabel = isNoteLockedForEditing() ? (currentRecordStatus === 'completed' ? 'OFFICE COMPLETE' : 'FINALISED') : 'DRAFT';
    var bodyRows = '';
    if (totals.fixedFee > 0) {
      bodyRows += '<tr><td>' + esc(line1) + '</td><td class="right">' + fc(totals.fixedFee) + '</td></tr>';
    }
    if (totals.mileageAmount > 0) {
      var ml = 'Mileage';
      if (totals.mileageMiles > 0) { ml += ' (' + totals.mileageMiles + ' mi \u00D7 ' + fc(totals.mileageRate) + ' /mi)'; }
      bodyRows += '<tr><td>' + ml + '</td><td class="right">' + fc(totals.mileageAmount) + '</td></tr>';
    }
    if (totals.parkingAmount > 0) {
      bodyRows += '<tr><td>Parking / disbursements</td><td class="right">' + fc(totals.parkingAmount) + '</td></tr>';
    }
    if (!bodyRows) {
      bodyRows = '<tr><td colspan="2" style="color:#64748b;">No charge lines (set fees in Step 2 — Billing review).</td></tr>';
    }

    return '<!DOCTYPE html><html><head><meta charset="utf-8"><style>' +
      'body{font-family:Arial,Helvetica,sans-serif;font-size:11pt;margin:20mm 15mm;color:#1e293b;}' +
      'h1{font-size:16pt;margin:0 0 4px;} .blurb{font-size:10pt;color:#64748b;margin:0 0 8px;}' +
      ' .status{font-size:10pt;padding:3px 10px;border-radius:4px;display:inline-block;margin-bottom:12px;background:#e2e8f0;font-weight:600;}' +
      ' .status-ready{background:#d1fae5;color:#065f46;}' +
      'table{width:100%;border-collapse:collapse;margin:10px 0;} th,td{padding:5px 8px;text-align:left;border-bottom:1px solid #e2e8f0;} th{background:#f8fafc;font-weight:600;font-size:10pt;}' +
      '.right{text-align:right;} .total-row{font-weight:700;border-top:2px solid #1e293b;} .grand{font-size:13pt;}' +
      '.header-grid{display:grid;grid-template-columns:1fr 1fr;gap:6px 24px;margin:12px 0;font-size:10pt;}' +
      '.header-grid dt{font-weight:600;color:#64748b;} .header-grid dd{margin:0;}' +
      '.footer{margin-top:20px;font-size:9pt;color:#94a3b8;border-top:1px solid #e2e8f0;padding-top:8px;}' +
      '@media print{body{margin:10mm;}}' +
      '</style></head><body>' +
      '<h1>Billing Summary</h1>' +
      '<p class="blurb">Reflects the same charge lines as the billing review and QuickFile preview, not LAA notional time rates from Section 9.</p>' +
      '<span class="status status-ready">' + statusLabel + '</span>' +
      '<dl class="header-grid">' +
        '<dt>Client</dt><dd>' + esc((d.surname || '').toUpperCase() + ', ' + (d.forename || '')) + '</dd>' +
        '<dt>Station</dt><dd>' + esc(d.policeStationName || d.policeStationId || '') + '</dd>' +
        '<dt>Date</dt><dd>' + esc(fmtDate(d.date)) + '</dd>' +
        '<dt>DSCC Ref</dt><dd>' + esc(formatDsccForPdf(d)) + '</dd>' +
        '<dt>UFN</dt><dd>' + esc(d.ufn || '\u2014') + '</dd>' +
        '<dt>Fee Earner</dt><dd>' + esc(d.feeEarnerName || '') + '</dd>' +
        '<dt>Firm</dt><dd>' + esc(d.firmName || '') + '</dd>' +
        '<dt>Matter Type</dt><dd>' + esc(d.matterTypeCode || '\u2014') + '</dd>' +
        '<dt>Outcome</dt><dd>' + esc(d.outcomeDecision || '\u2014') + '</dd>' +
        '<dt>Arrival</dt><dd>' + esc(d.timeArrival || '\u2014') + '</dd>' +
        '<dt>Departure</dt><dd>' + esc(d.timeDeparture || '\u2014') + '</dd>' +
      '</dl>' +
      '<table>' +
        '<thead><tr><th>Item</th><th class="right">Amount</th></tr></thead><tbody>' +
        bodyRows +
        '<tr class="total-row"><td>Subtotal (ex VAT)</td><td class="right">' + fc(totals.subTotal) + '</td></tr>' +
        '<tr><td>VAT (' + vatPct + '%)</td><td class="right">' + fc(totals.vatTotal) + '</td></tr>' +
        '<tr class="total-row grand"><td>Total (inc. VAT)</td><td class="right">' + fc(totals.grandTotal) + '</td></tr>' +
        '</tbody></table>' +
      '<div class="footer">Generated: ' + new Date().toLocaleString('en-GB') + ' | CustodyNote Billing Summary</div>' +
      '</body></html>';
  }

  var previewPdf = printAttendanceNote;

  /**
   * After Template Manager "Use template": insert rendered text into a form field or clipboard.
   */
  function applyTemplateManagerOutput(subject, content, meta) {
    var subj = String(subject || '').trim();
    var body = String(content || '');
    var overlay = document.createElement('div');
    overlay.className = 'cn-confirm-overlay';
    var box = document.createElement('div');
    box.className = 'cn-confirm-box';
    box.style.maxWidth = '440px';
    var warn = (meta && meta.missing && meta.missing.length)
      ? '<p style="margin:0 0 10px;font-size:12px;color:#b45309;background:#fffbeb;padding:8px 10px;border-radius:6px;border:1px solid #fde68a;">No data for placeholders: <code style="font-size:11px;">' +
        meta.missing.map(function(k) { return '[' + String(k).replace(/</g, '') + ']'; }).join(', ') +
        '</code> — those were left blank.</p>'
      : '';
    box.innerHTML =
      '<h3 style="margin:0 0 8px;font-size:1.05rem;">Insert template</h3>' +
      '<p style="margin:0 0 12px;font-size:13px;color:#64748b;">Choose where to place the rendered text.</p>' +
      warn +
      '<label class="form-label" for="tpl-insert-target">Destination</label>' +
      '<select id="tpl-insert-target" class="form-input" style="width:100%;margin-bottom:12px;">' +
      '<option value="disclosureNarrative">Narrative / Disclosure Notes</option>' +
      '<option value="clientInstructions">Summary of client instructions</option>' +
      '<option value="notesToOffice">Notes to Office / Firm</option>' +
      '<option value="arrivalNotes">General Notes</option>' +
      '<option value="iv0_notes">Interview 1 notes</option>' +
      '<option value="clipboard">Copy to clipboard only</option>' +
      '</select>' +
      '<div id="tpl-append-row" style="margin-bottom:12px;font-size:13px;">' +
      '<label style="margin-right:12px;"><input type="radio" name="tpl-mode" value="append" checked> Append to existing</label>' +
      '<label><input type="radio" name="tpl-mode" value="replace"> Replace field</label>' +
      '</div>' +
      '<div style="display:flex;gap:8px;justify-content:flex-end;">' +
      '<button type="button" class="btn btn-secondary" id="tpl-insert-cancel">Cancel</button>' +
      '<button type="button" class="btn btn-primary" id="tpl-insert-go">Insert</button>' +
      '</div>';
    overlay.appendChild(box);
    document.body.appendChild(overlay);

    var sel = box.querySelector('#tpl-insert-target');
    var appendRow = box.querySelector('#tpl-append-row');
    function syncModeVisibility() {
      appendRow.style.display = sel.value === 'clipboard' ? 'none' : '';
    }
    sel.addEventListener('change', syncModeVisibility);
    syncModeVisibility();

    function close() {
      try { document.body.removeChild(overlay); } catch (_) {}
    }
    box.querySelector('#tpl-insert-cancel').addEventListener('click', close);
    overlay.addEventListener('click', function(e) { if (e.target === overlay) close(); });

    box.querySelector('#tpl-insert-go').addEventListener('click', function() {
      var target = sel.value;
      var modeEl = box.querySelector('input[name="tpl-mode"]:checked');
      var append = modeEl && modeEl.value === 'append';

      if (target === 'clipboard') {
        var full = (subj ? 'Subject: ' + subj + '\n\n' : '') + body;
        if (navigator.clipboard && navigator.clipboard.writeText) {
          navigator.clipboard.writeText(full).then(function() {
            showToast('Copied to clipboard', 'success');
            close();
          }).catch(function() {
            showToast('Could not copy to clipboard', 'error');
          });
        } else {
          showToast('Clipboard not available', 'error');
        }
        return;
      }

      var block = body;
      if (subj) {
        block = subj + '\n\n' + body;
      }

      if (target === 'iv0_notes') {
        if (!formData.interviews) formData.interviews = [{}];
        if (!formData.interviews[0]) formData.interviews[0] = {};
        var iv0 = formData.interviews[0];
        var prevIv = String(iv0.notes || '').trim();
        var mergedIv = append && prevIv ? prevIv + '\n\n' + block : block;
        iv0.notes = mergedIv;
        setFieldValue('iv0_notes', mergedIv);
        if (typeof quietSave === 'function') quietSave();
        showToast('Template inserted into interview notes', 'success');
        close();
        return;
      }

      var existing = String(formData[target] || '').trim();
      var newVal = append && existing ? existing + '\n\n' + block : block;
      setFieldValue(target, newVal);
      if (typeof quietSave === 'function') quietSave();
      showToast('Template inserted', 'success');
      close();
    });
  }

  function copyTextToClipboardWithFeedback(text, successMessage) {
    successMessage = successMessage || 'Copied to clipboard';
    if (navigator.clipboard && navigator.clipboard.writeText) {
      return navigator.clipboard.writeText(text).then(function() {
        showToast(successMessage, 'success');
        return true;
      }).catch(function() {
        showToast('Could not copy to clipboard', 'error');
        return false;
      });
    }
    try {
      var ta = document.createElement('textarea');
      ta.value = text;
      ta.style.position = 'fixed';
      ta.style.opacity = '0';
      document.body.appendChild(ta);
      ta.select();
      document.execCommand('copy');
      document.body.removeChild(ta);
      showToast(successMessage, 'success');
      return Promise.resolve(true);
    } catch (_) {
      showToast('Could not copy to clipboard', 'error');
      return Promise.resolve(false);
    }
  }

  /** Copy-only replacement for legacy Outlook Web compose launch (v1.6.21). */
  function copyOutlookComposeFields(toEmail, subject, body, opts) {
    opts = opts || {};
    var to = String(toEmail || '').trim();
    if (!to && !opts.allowEmptyTo) {
      showToast('Add a recipient email address first.', 'error');
      return Promise.resolve(false);
    }
    var bodyStr = String(body || '');
    if (bodyStr.length > 4000) bodyStr = bodyStr.slice(0, 4000) + '\n\n[continued]';
    var lines = [];
    if (to) lines.push('To: ' + to);
    lines.push('Subject: ' + String(subject || ''));
    lines.push('');
    lines.push(bodyStr);
    var msg = opts.successToast || 'Copied — paste into Outlook';
    return copyTextToClipboardWithFeedback(lines.join('\n'), msg);
  }

  function closeAttendancePickerModal() {
    document.querySelectorAll('.attendance-picker-overlay').forEach(function(el) {
      try { el.remove(); } catch (_) {}
    });
  }

  /**
   * Fixed viewport overlay for picking an attendance record.
   * opts: { title, hint, emptyState: { message, blankLabel, onBlank, createLabel, onCreate }, onSelect(id), onCancel() }
   */
  function openAttendancePickerModal(opts) {
    opts = opts || {};
    closeAttendancePickerModal();
    var overlay = document.createElement('div');
    overlay.className = 'attendance-picker-overlay';
    overlay.setAttribute('aria-label', opts.title || 'Select attendance');
    overlay.innerHTML =
      '<div class="sections-index-content attendance-picker-content">' +
        '<h3>' + esc(opts.title || 'Select attendance') + '</h3>' +
        (opts.hint ? '<p class="attendance-picker-hint">' + opts.hint + '</p>' : '') +
        '<ul class="attendance-picker-list" data-role="list"></ul>' +
        '<div class="attendance-picker-empty-actions hidden" data-role="empty-actions"></div>' +
        '<button type="button" class="btn btn-secondary attendance-picker-cancel" style="margin-top:0.75rem;width:100%;">Cancel</button>' +
      '</div>';
    document.body.appendChild(overlay);

    var listEl = overlay.querySelector('[data-role="list"]');
    var emptyActions = overlay.querySelector('[data-role="empty-actions"]');
    var closed = false;

    function close() {
      if (closed) return;
      closed = true;
      try { overlay.remove(); } catch (_) {}
    }

    function finish(id) {
      close();
      if (id != null && opts.onSelect) opts.onSelect(id);
      else if (opts.onCancel) opts.onCancel();
    }

    overlay.querySelector('.attendance-picker-cancel').addEventListener('click', function() { finish(null); });
    overlay.addEventListener('click', function(e) { if (e.target === overlay) finish(null); });

    function showEmptyActions(message) {
      listEl.innerHTML = '<li class="home-recent-empty">' + esc(message || 'No attendances yet.') + '</li>';
      if (!opts.emptyState) return;
      emptyActions.classList.remove('hidden');
      emptyActions.innerHTML = '';
      if (opts.emptyState.blankLabel && opts.emptyState.onBlank) {
        var blankBtn = document.createElement('button');
        blankBtn.type = 'button';
        blankBtn.className = 'btn btn-secondary';
        blankBtn.style.cssText = 'width:100%;margin-bottom:0.5rem;';
        blankBtn.textContent = opts.emptyState.blankLabel;
        blankBtn.addEventListener('click', function() {
          close();
          opts.emptyState.onBlank();
        });
        emptyActions.appendChild(blankBtn);
      }
      if (opts.emptyState.createLabel && opts.emptyState.onCreate) {
        var createBtn = document.createElement('button');
        createBtn.type = 'button';
        createBtn.className = 'btn';
        createBtn.style.cssText = 'width:100%;margin-bottom:0.5rem;';
        createBtn.textContent = opts.emptyState.createLabel;
        createBtn.addEventListener('click', function() {
          close();
          opts.emptyState.onCreate();
        });
        emptyActions.appendChild(createBtn);
      }
    }

    listEl.innerHTML = '<li class="home-recent-empty">Loading\u2026</li>';
    var listFn = window.api && (window.api.attendanceListFull || window.api.attendanceList);
    if (!listFn) {
      showEmptyActions('Could not load attendances.');
      return overlay;
    }
    listFn().then(function(rows) {
      if (!rows || !rows.length) {
        showEmptyActions(opts.emptyState && opts.emptyState.message ? opts.emptyState.message : 'No attendances yet.');
        return;
      }
      emptyActions.classList.add('hidden');
      var sorted = rows.slice().sort(function(a, b) { return (b.updated_at || b.created_at || '').localeCompare(a.updated_at || a.created_at || ''); });
      listEl.innerHTML = sorted.map(function(r) {
        var name = (r.client_name && String(r.client_name).trim()) || 'Draft (no name)';
        var station = r.station_name || '';
        var date = r.attendance_date || '';
        if (date) {
          var dm = String(date).match(/^(\d{4})-(\d{2})-(\d{2})/);
          if (dm) date = dm[3] + '/' + dm[2] + '/' + dm[1];
        }
        var meta = [station, date].filter(Boolean).join(' \u00B7 ');
        return '<li class="attendance-picker-item" data-id="' + r.id + '"><span class="picker-item-name">' + esc(name) + '</span><span class="picker-item-meta">' + esc(meta) + '</span></li>';
      }).join('');
      listEl.querySelectorAll('.attendance-picker-item').forEach(function(li) {
        li.addEventListener('click', function() {
          var id = parseInt(li.dataset.id, 10);
          finish(isNaN(id) ? null : id);
        });
      });
    }).catch(function() {
      listEl.innerHTML = '<li class="home-recent-empty">Failed to load list.</li>';
      showToast('Failed to load attendances', 'error');
    });
    return overlay;
  }

  function showLicenceGateToast() {
    if (window.__licenceExpired) {
      showToast('Your subscription has expired. Renew at custodynote.com/pricing to create new records.', 'warning', 5000);
      return true;
    }
    return false;
  }

  function startNewAttendanceFromHome() {
    if (showLicenceGateToast()) {
      return;
    }
    currentStandaloneSectionId = null;
    formData = {};
    currentAttendanceId = null;
    currentSectionIdx = 0;
    activeFormSections = formSections;
    formData.attendanceMode = 'custody';
    formData.workType = 'First Police Station Attendance';
    formData._formType = 'attendance';
    prefillDefaults();
    renderForm(formData);
    showView('new');
  }

  /* ═══════════════════════════════════════════════
     STANDALONE: VIDEO CAPTURE / VIDEO ID PARADE
     (Attach existing attendance or create new draft)
     ═══════════════════════════════════════════════ */

  function showStandaloneAttachChooser(kindTitle) {
    return new Promise(function(resolve) {
      var overlay = document.createElement('div');
      overlay.className = 'attendance-picker-overlay';
      overlay.innerHTML =
        '<div class="sections-index-content" style="max-width:420px;width:92%;">' +
          '<h3 style="margin-top:0;">' + esc(kindTitle) + '</h3>' +
          '<p class="attendance-picker-hint">Choose how you want to proceed.</p>' +
          '<button type="button" class="btn btn-secondary" id="vid-attach-existing" style="width:100%;margin-bottom:0.5rem;">Attach to an existing attendance</button>' +
          '<button type="button" class="btn" id="vid-new-draft" style="width:100%;margin-bottom:0.5rem;">New client (create new draft)</button>' +
          '<button type="button" class="btn btn-secondary" id="vid-cancel" style="width:100%;">Cancel</button>' +
        '</div>';
      document.body.appendChild(overlay);

      function cleanup(val) {
        try { overlay.remove(); } catch (_) {}
        resolve(val);
      }

      overlay.addEventListener('click', function(e) {
        if (e.target === overlay) cleanup(null);
      });
      overlay.querySelector('#vid-attach-existing')?.addEventListener('click', function() { cleanup('existing'); });
      overlay.querySelector('#vid-new-draft')?.addEventListener('click', function() { cleanup('new'); });
      overlay.querySelector('#vid-cancel')?.addEventListener('click', function() { cleanup(null); });
    });
  }

  function pickAttendanceIdForStandalone(titleText) {
    return new Promise(function(resolve) {
      openAttendancePickerModal({
        title: titleText || 'Select attendance',
        hint: 'Choose an attendance to attach this section to.',
        onSelect: function(id) { resolve(id); },
        onCancel: function() { resolve(null); },
      });
    });
  }

  function openStandaloneSectionForAttendance(attendanceId, standaloneId, fallbackData) {
    currentStandaloneSectionId = standaloneId;
    currentAttendanceId = attendanceId;
    // Show form view immediately for responsiveness. If we already have draft data,
    // render it right away while we fetch the saved record (file number etc.).
    showView('new');
    if (fallbackData && typeof fallbackData === 'object') {
      formData = JSON.parse(JSON.stringify(fallbackData));
      activeFormSections = formSections;
      currentSectionIdx = 0;
      renderForm(formData);
    }
    window.api.attendanceGet(attendanceId).then(function(row) {
      currentRecordStatus = row ? row.status : null;
      currentRecordArchived = !!(row && row.archived_at);
      formData = row && row.data ? safeJson(row.data) : {};
      activeFormSections = formSections;
      currentSectionIdx = 0;
      renderForm(formData);
    }).catch(function(e) {
      showToast('Failed to load attendance: ' + (e && e.message), 'error');
    });
  }

  function createNewDraftAndOpenStandalone(standaloneId) {
    var now = new Date();
    var base = {
      _formType: 'attendance',
      workType: 'First Police Station Attendance',
      date: now.toISOString().slice(0, 10),
      _draftNonce: String(Date.now()),
      _createdViaStandalone: standaloneId
    };
    showToast('Creating new draft…', 'info');
    window.api.attendanceSave({ id: null, data: base, status: 'draft' }).then(function(id) {
      // attendance-save normally returns a number; handle unexpected shapes safely.
      if (id && typeof id === 'object' && id.error) {
        showToast(id.message || 'Could not create draft', 'error');
        return;
      }
      var newId = null;
      if (typeof id === 'number') newId = id;
      else if (typeof id === 'string') newId = parseInt(id, 10);
      else if (id && typeof id === 'object' && typeof id.id === 'number') newId = id.id;
      if (!newId || isNaN(newId)) {
        showToast('Could not create draft (no id returned)', 'error');
        return;
      }
      openStandaloneSectionForAttendance(newId, standaloneId, base);
    }).catch(function(e) {
      showToast('Failed to create draft: ' + (e && e.message), 'error');
    });
  }

  function openVideoStandaloneFromHome(standaloneId, title) {
    showStandaloneAttachChooser(title || 'Video section').then(function(choice) {
      if (!choice) return;
      if (choice === 'existing') {
        pickAttendanceIdForStandalone('Select attendance for ' + (title || 'video section')).then(function(id) {
          if (!id) return;
          openStandaloneSectionForAttendance(id, standaloneId);
        });
      } else if (choice === 'new') {
        createNewDraftAndOpenStandalone(standaloneId);
      }
    });
  }

  /* ═══════════════════════════════════════════════
     POLICE STATION DOCUMENT GENERATORS
     ═══════════════════════════════════════════════ */

  function printGeneratedDoc(html) {
    // H2 — route through the main process's preview-pdf-from-html channel,
    // which uses BrowserWindow.loadFile() on a temp HTML file. Avoids the
    // window.open() + document.write() data-URL/size pitfalls and works for
    // large cover letters / authority letters / generated forms.
    if (window.api && typeof window.api.previewPdfFromHtml === 'function') {
      window.api.previewPdfFromHtml({ html: html }).catch(function(err) {
        console.warn('[printGeneratedDoc] preview-pdf-from-html failed, falling back to popup', err);
        _printGeneratedDocPopupFallback(html);
      });
      return;
    }
    _printGeneratedDocPopupFallback(html);
  }
  function _printGeneratedDocPopupFallback(html) {
    var w = window.open('', '_blank', 'width=900,height=700');
    if (!w) { showToast('Please allow pop-ups for this app to print documents', 'error'); return; }
    w.document.write(html);
    w.document.close();
    w.focus();
    setTimeout(function() { try { w.print(); } catch (_) {} }, 400);
  }

  /** Billing / LAA: open HTML in a window without forcing the print dialog. */
  function openHtmlPreviewWindow(html) {
    const w = window.open('', '_blank', 'width=900,height=700');
    if (!w) {
      showToast('Please allow pop-ups to preview documents', 'error');
      return;
    }
    w.document.write(html);
    w.document.close();
    w.focus();
  }
  window.openHtmlPreviewWindow = openHtmlPreviewWindow;
  window.esc = esc;
  window.formatDateGB = formatDateGB;

