    /**
     * Copy a licence key to the clipboard, then auto-clear it 30 seconds
     * later. Never logs the key. Fails silently if the clipboard API
     * refuses (e.g. window not focused). Used by the admin reveal flow.
     */
    function _adminCopyLicenceKeyToClipboard(licenceKey) {
      if (typeof licenceKey !== 'string' || !licenceKey) {
        showToast('No licence key to copy', 'error');
        return;
      }
      function clearLater() {
        setTimeout(function () {
          try {
            if (navigator && navigator.clipboard && navigator.clipboard.writeText) {
              // Best-effort: only clear if the clipboard still contains our key.
              navigator.clipboard.readText().then(function (current) {
                if (current === licenceKey) {
                  navigator.clipboard.writeText('').catch(function () {});
                }
              }).catch(function () {});
            }
          } catch (_) {}
        }, 30000);
      }
      try {
        if (navigator && navigator.clipboard && navigator.clipboard.writeText) {
          navigator.clipboard.writeText(licenceKey).then(function () {
            showToast('Licence key copied to clipboard. It will auto-clear in 30 seconds.', 'success');
            clearLater();
          }).catch(function () {
            showToast('Could not access clipboard. Use the Resend button to email the key instead.', 'error');
          });
          return;
        }
      } catch (_) {}
      showToast('Clipboard not available. Use the Resend button to email the key instead.', 'error');
    }

    (function initAdminLicencePanel() {
      if (!window.custodyNote) return;
      var panel = document.getElementById('admin-licence-panel');
      var setupSection = document.getElementById('admin-setup-section');
      var loginSection = document.getElementById('admin-login-section');
      var contentSection = document.getElementById('admin-content-section');
      var setupTokenInp = document.getElementById('admin-setup-token-inp');
      var setupPasswordInp = document.getElementById('admin-setup-password-inp');
      var setupBtn = document.getElementById('admin-setup-btn');
      var setupMsg = document.getElementById('admin-setup-msg');
      var pwInp = document.getElementById('admin-password-inp');
      var loginBtn = document.getElementById('admin-login-btn');
      var loginMsg = document.getElementById('admin-login-msg');
      var searchInp = document.getElementById('admin-search-inp');
      var searchBtn = document.getElementById('admin-search-btn');
      var syncBtn = document.getElementById('admin-sync-btn');
      var syncMsg = document.getElementById('admin-sync-msg');
      var resultsEl = document.getElementById('admin-results');
      var closeBtn = document.getElementById('admin-close-btn');
      if (!panel || !loginSection || !contentSection) return;

      function showContent(show) {
        if (setupSection) setupSection.style.display = 'none';
        loginSection.style.display = show ? 'none' : 'block';
        contentSection.style.display = show ? 'block' : 'none';
      }

      function escapeHtml(s) {
        if (!s) return '';
        return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
      }
      function doSearch() {
        var q = (searchInp && searchInp.value) ? searchInp.value.trim() : '';
        custodyNote.adminSearch(q).then(function(r) {
          if (!r || !r.items) { resultsEl.innerHTML = '<p>No results</p>'; return; }
          var html = '<table style="width:100%;border-collapse:collapse;"><tr><th style="text-align:left;padding:0.35rem;">Email</th><th style="text-align:left;">Key</th><th>Status</th><th>Created</th><th></th></tr>';
          r.items.forEach(function(it) {
            var date = it.createdAt ? new Date(it.createdAt).toLocaleDateString('en-GB') : '-';
            html += '<tr><td style="padding:0.35rem;">' + escapeHtml(it.email || '') + '</td><td><code>' + escapeHtml(it.licenceKeyMasked || '') + '</code></td><td>' + escapeHtml(it.status || '') + '</td><td>' + date + '</td><td><button type="button" class="btn btn-small admin-reveal-btn" data-id="' + escapeHtml(it.id) + '">Reveal</button> <button type="button" class="btn btn-small admin-resend-btn" data-id="' + escapeHtml(it.id) + '">Resend</button></td></tr>';
          });
          html += '</table>';
          resultsEl.innerHTML = html;
          resultsEl.querySelectorAll('.admin-reveal-btn').forEach(function(b) {
            b.addEventListener('click', function() {
              custodyNote.adminRevealLicence(b.dataset.id).then(function(rec) {
                if (rec && rec.licence_key) {
                  // Security: never display the full licence key in a toast
                  // (screenshot/screen-recording risk; licence key is also
                  // the secret used to derive the cloud key escrow). Copy
                  // to clipboard with a 30-second auto-clear and tell the
                  // operator that's where it went.
                  _adminCopyLicenceKeyToClipboard(rec.licence_key);
                } else if (rec && rec.error) {
                  showToast(rec.error, 'error');
                }
              });
            });
          });
          resultsEl.querySelectorAll('.admin-resend-btn').forEach(function(b) {
            b.addEventListener('click', function() {
              custodyNote.adminResend(b.dataset.id).then(function(r) {
                showToast(r && r.message ? r.message : 'Sent');
              });
            });
          });
        });
      }

      custodyNote.adminHasPassword().then(function(has) {
        if (has) {
          if (setupSection) setupSection.style.display = 'none';
          showContent(false);
        } else {
          if (setupSection) {
            setupSection.style.display = 'block';
            loginSection.style.display = 'none';
            contentSection.style.display = 'none';
          } else {
            loginMsg.textContent = 'Admin not configured. Set ADMIN_SETUP_TOKEN and run setup.';
          }
        }
      });

      if (setupBtn) setupBtn.addEventListener('click', function() {
        var token = setupTokenInp ? setupTokenInp.value.trim() : '';
        var pw = setupPasswordInp ? setupPasswordInp.value : '';
        if (!token || token.length < 16) { setupMsg.textContent = 'Setup token must be at least 16 characters'; return; }
        if (!pw || pw.length < 8) { setupMsg.textContent = 'Password must be at least 8 characters'; return; }
        setupMsg.textContent = '';
        custodyNote.adminSetPassword({ token: token, password: pw }).then(function(r) {
          if (r && r.ok) {
            setupSection.style.display = 'none';
            loginSection.style.display = 'block';
            setupMsg.textContent = '';
            setupTokenInp.value = ''; setupPasswordInp.value = '';
          } else {
            setupMsg.textContent = (r && r.error) ? r.error : 'Setup failed';
          }
        }).catch(function() { setupMsg.textContent = 'Setup failed'; });
      });

      if (loginBtn) loginBtn.addEventListener('click', function() {
        var pw = pwInp ? pwInp.value : '';
        custodyNote.adminLogin(pw).then(function(r) {
          if (r && r.ok) { showContent(true); loginMsg.textContent = ''; doSearch(); }
          else { loginMsg.textContent = (r && r.error) ? r.error : 'Invalid'; }
        });
      });

      if (searchBtn) searchBtn.addEventListener('click', doSearch);
      if (searchInp) searchInp.addEventListener('keydown', function(e) { if (e.key === 'Enter') doSearch(); });

      if (syncBtn) syncBtn.addEventListener('click', function() {
        syncMsg.textContent = 'Syncing…';
        custodyNote.adminSync().then(function(r) {
          syncMsg.textContent = r && r.ok ? 'Synced ' + (r.synced || 0) + ' records.' : ((r && r.reason) ? r.reason : 'Sync failed');
        });
      });

      // ── Tab switching ──
      var tabs = document.querySelectorAll('#admin-tabs .admin-tab');
      var tabSearch = document.getElementById('admin-tab-search');
      var tabDashboard = document.getElementById('admin-tab-dashboard');
      tabs.forEach(function(tab) {
        tab.addEventListener('click', function() {
          tabs.forEach(function(t) {
            t.classList.remove('active');
            t.style.borderBottom = 'none';
            t.style.color = '#64748b';
            t.style.fontWeight = '500';
          });
          tab.classList.add('active');
          tab.style.borderBottom = '2px solid #3b82f6';
          tab.style.color = '#3b82f6';
          tab.style.fontWeight = '600';
          var target = tab.dataset.tab;
          if (tabSearch) tabSearch.style.display = target === 'search' ? 'block' : 'none';
          if (tabDashboard) tabDashboard.style.display = target === 'dashboard' ? 'block' : 'none';
          if (target === 'dashboard') loadDashboard();
        });
      });

      // ── Dashboard ──
      var _dashData = null;
      var dashStats = document.getElementById('admin-dash-stats');
      var dashTable = document.getElementById('admin-dash-table');
      var dashStatus = document.getElementById('admin-dash-status');
      var dashFilter = document.getElementById('admin-dash-filter');
      var dashRefresh = document.getElementById('admin-dash-refresh');
      var dashExport = document.getElementById('admin-dash-export');

      function statCard(label, value, color) {
        return '<div style="background:' + (color || '#f8fafc') + ';border:1px solid #e2e8f0;border-radius:8px;padding:0.75rem;text-align:center;">' +
          '<div style="font-size:1.5rem;font-weight:700;color:#1e293b;">' + value + '</div>' +
          '<div style="font-size:0.75rem;color:#64748b;margin-top:0.15rem;">' + escapeHtml(label) + '</div></div>';
      }

      function renderDashStats(stats) {
        if (!dashStats) return;
        dashStats.innerHTML =
          statCard('Total Users', stats.total || 0, '#f0f9ff') +
          statCard('Active', stats.active || 0, '#ecfdf5') +
          statCard('Trialing', stats.trialing || 0, '#fffbeb') +
          statCard('Cancelled', stats.cancelled || 0, '#fff1f2') +
          statCard('Expired', stats.expired || 0, '#fef2f2') +
          statCard('No Sub', stats.noSubscription || 0, '#f8fafc');
      }

      function renderDashTable(licences) {
        if (!dashTable) return;
        var filter = dashFilter ? dashFilter.value.trim().toLowerCase() : '';
        var filtered = filter ? licences.filter(function(l) {
          return (l.email || '').toLowerCase().indexOf(filter) !== -1 ||
                 (l.licenceKey || '').toLowerCase().indexOf(filter) !== -1 ||
                 (l.name || '').toLowerCase().indexOf(filter) !== -1;
        }) : licences;

        if (filtered.length === 0) {
          dashTable.innerHTML = '<p style="color:#94a3b8;">No licences found' + (filter ? ' matching filter' : '') + '.</p>';
          return;
        }

        var html = '<table style="width:100%;border-collapse:collapse;"><thead><tr>' +
          '<th style="text-align:left;padding:0.4rem 0.5rem;border-bottom:2px solid #e2e8f0;font-size:0.78rem;color:#64748b;">Email</th>' +
          '<th style="text-align:left;padding:0.4rem 0.5rem;border-bottom:2px solid #e2e8f0;font-size:0.78rem;color:#64748b;">Name</th>' +
          '<th style="text-align:left;padding:0.4rem 0.5rem;border-bottom:2px solid #e2e8f0;font-size:0.78rem;color:#64748b;">Key</th>' +
          '<th style="text-align:left;padding:0.4rem 0.5rem;border-bottom:2px solid #e2e8f0;font-size:0.78rem;color:#64748b;">Status</th>' +
          '<th style="text-align:left;padding:0.4rem 0.5rem;border-bottom:2px solid #e2e8f0;font-size:0.78rem;color:#64748b;">Plan</th>' +
          '<th style="text-align:left;padding:0.4rem 0.5rem;border-bottom:2px solid #e2e8f0;font-size:0.78rem;color:#64748b;">Last app use</th>' +
          '<th style="text-align:left;padding:0.4rem 0.5rem;border-bottom:2px solid #e2e8f0;font-size:0.78rem;color:#64748b;">Created</th>' +
          '<th style="padding:0.4rem 0.5rem;border-bottom:2px solid #e2e8f0;font-size:0.78rem;color:#64748b;"></th>' +
          '</tr></thead><tbody>';

        filtered.forEach(function(l, i) {
          var bg = i % 2 === 0 ? '#fff' : '#f8fafc';
          var statusColor = l.subscriptionStatus === 'active' ? '#16a34a' : l.subscriptionStatus === 'trialing' ? '#d97706' : l.subscriptionStatus === 'cancelled' ? '#dc2626' : '#94a3b8';
          var date = l.createdAt ? new Date(l.createdAt).toLocaleDateString('en-GB') : '-';
          var maskedKey = l.licenceKey ? l.licenceKey.slice(0, 7) + '****' + l.licenceKey.slice(-4) : '-';
          var lastUse = l.lastAppUseAt ? new Date(l.lastAppUseAt).toLocaleString('en-GB') : '—';
          var idleNote = l.licenceRevokeIdleWarning
            ? '<div style="font-size:0.72rem;color:#b45309;margin-top:0.25rem;max-width:14rem;">' + escapeHtml(l.licenceRevokeIdleWarning) + '</div>'
            : '';
          html += '<tr style="background:' + bg + ';">' +
            '<td style="padding:0.35rem 0.5rem;">' + escapeHtml(l.email || '') + '</td>' +
            '<td style="padding:0.35rem 0.5rem;">' + escapeHtml(l.name || '') + '</td>' +
            '<td style="padding:0.35rem 0.5rem;"><code style="font-size:0.78rem;" class="dash-key" data-full="' + escapeHtml(l.licenceKey || '') + '">' + escapeHtml(maskedKey) + '</code></td>' +
            '<td style="padding:0.35rem 0.5rem;"><span style="color:' + statusColor + ';font-weight:600;">' + escapeHtml(l.subscriptionStatus || 'none') + '</span></td>' +
            '<td style="padding:0.35rem 0.5rem;">' + escapeHtml(l.plan || '-') + '</td>' +
            '<td style="padding:0.35rem 0.5rem;vertical-align:top;">' + escapeHtml(lastUse) + idleNote + '</td>' +
            '<td style="padding:0.35rem 0.5rem;">' + date + '</td>' +
            '<td style="padding:0.35rem 0.5rem;white-space:nowrap;">' +
            '<button type="button" class="btn btn-small dash-reveal" data-key="' + escapeHtml(l.licenceKey || '') + '" style="font-size:0.75rem;">Reveal</button> ' +
            '<button type="button" class="btn btn-small dash-resend" data-email="' + escapeHtml(l.email || '') + '" data-key="' + escapeHtml(l.licenceKey || '') + '" style="font-size:0.75rem;">Send</button>' +
            '</td></tr>';
        });
        html += '</tbody></table>';
        dashTable.innerHTML = html;

        dashTable.querySelectorAll('.dash-reveal').forEach(function(btn) {
          btn.addEventListener('click', function() {
            var keyEl = btn.closest('tr').querySelector('.dash-key');
            if (keyEl) {
              var full = keyEl.dataset.full;
              if (keyEl.textContent === full) {
                keyEl.textContent = full.slice(0, 7) + '****' + full.slice(-4);
              } else {
                keyEl.textContent = full;
              }
            }
          });
        });

        dashTable.querySelectorAll('.dash-resend').forEach(function(btn) {
          btn.addEventListener('click', function() {
            var email = btn.dataset.email;
            var key = btn.dataset.key;
            if (!email || !key) return;
            btn.disabled = true;
            btn.textContent = 'Sending…';
            custodyNote.adminResendToEmail({ email: email, licenceKey: key }).then(function(r) {
              btn.disabled = false;
              btn.textContent = 'Send';
              if (r && r.ok) showToast('Key sent to ' + email, 'success');
              else showToast((r && r.error) || 'Failed to send', 'error');
            }).catch(function() {
              btn.disabled = false;
              btn.textContent = 'Send';
              showToast('Failed to send', 'error');
            });
          });
        });
      }

      function loadDashboard() {
        if (dashStatus) dashStatus.textContent = 'Loading licence data from server…';
        if (dashTable) dashTable.innerHTML = '';
        if (dashStats) dashStats.innerHTML = '';
        custodyNote.adminDashboard().then(function(r) {
          if (!r || !r.ok) {
            if (dashStatus) dashStatus.textContent = (r && r.error) || 'Failed to load dashboard';
            return;
          }
          _dashData = r.licences || [];
          if (dashStatus) dashStatus.textContent = r.licences.length + ' users loaded.';
          renderDashStats(r.stats || {});
          renderDashTable(_dashData);
        }).catch(function(e) {
          if (dashStatus) dashStatus.textContent = 'Error: ' + (e.message || 'unknown');
        });
      }

      if (dashFilter) dashFilter.addEventListener('input', function() {
        if (_dashData) renderDashTable(_dashData);
      });
      if (dashRefresh) dashRefresh.addEventListener('click', loadDashboard);
      if (dashExport) dashExport.addEventListener('click', function() {
        if (!_dashData || !_dashData.length) { showToast('No data to export', 'warning'); return; }
        var csv = 'Email,Name,Licence Key,Status,Plan,Cloud Backup,Last App Use,Idle Policy Note,Created,Expires\n';
        _dashData.forEach(function(l) {
          csv += [l.email, l.name, l.licenceKey, l.subscriptionStatus || 'none', l.plan || '', l.cloudBackup ? 'Yes' : 'No', l.lastAppUseAt || '', l.licenceRevokeIdleWarning || '', l.createdAt || '', l.expiresAt || ''].map(function(v) {
            return '"' + String(v || '').replace(/"/g, '""') + '"';
          }).join(',') + '\n';
        });
        var blob = new Blob([csv], { type: 'text/csv' });
        var a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = 'custody-note-licences-' + new Date().toISOString().slice(0, 10) + '.csv';
        a.click();
        URL.revokeObjectURL(a.href);
      });

      if (closeBtn) closeBtn.addEventListener('click', function() {
        panel.style.display = 'none';
      });
      panel.addEventListener('click', function(e) {
        if (e.target === panel) panel.style.display = 'none';
      });
    })();

