  /* ─── First-launch setup (single step) ─── */
  function initFirstLaunchModal() {
    var modal = document.getElementById('first-launch-modal');
    if (!modal) return;
    modal.style.display = 'flex';

    var _flSettings = {};

    function showStep(n) {
      modal.querySelectorAll('.fl-step').forEach(function(s) { s.style.display = 'none'; });
      var step = document.getElementById('fl-step-' + n);
      if (step) step.style.display = '';
    }

    /* Step 1 -> Step 2 */
    document.getElementById('fl-next-1')?.addEventListener('click', function() {
      var name = (document.getElementById('fl-fee-earner-name').value || '').trim();
      var pin = (document.getElementById('fl-dscc-pin').value || '').trim();
      if (!name) { showToast('Please enter your fee earner name', 'error'); return; }
      if (!pin) { showToast('Please enter your DSCC PIN/number', 'error'); return; }
      var email = (document.getElementById('fl-email').value || '').trim();
      var officePostcode = (document.getElementById('fl-office-postcode')?.value || '').trim();
      _flSettings = { feeEarnerNameDefault: name, dsccPin: pin };
      if (email) _flSettings.email = email;
      if (officePostcode) _flSettings.officePostcode = officePostcode;
      window.api.setSettings(_flSettings).then(function() {
        window._appSettingsCache = Object.assign({}, window._appSettingsCache || {}, _flSettings);
        showStep(2);

        if (window.api.detectCloudFolders) {
          window.api.detectCloudFolders().then(function(folders) {
            if (folders && folders.length) {
              var best = folders[0];
              document.getElementById('fl-backup-auto').style.display = '';
              document.getElementById('fl-backup-manual').style.display = 'none';
              document.getElementById('fl-backup-path').textContent = best.name || best.path;
              window.api.setSettings({ offsiteBackupFolder: best.path });
            }
          }).catch(function(e) { console.error('[detect-cloud-folders]', e); });
        }
      }).catch(function(e) { showToast('Failed to save settings', 'error'); console.error('[fl-settings]', e); });
    });

    /* Step 2: Choose backup folder manually */
    document.getElementById('fl-backup-choose')?.addEventListener('click', function() {
      if (window.api.chooseFolder) {
        window.api.chooseFolder().then(function(folder) {
          if (folder) {
            window.api.setSettings({ offsiteBackupFolder: folder });
            document.getElementById('fl-backup-auto').style.display = '';
            document.getElementById('fl-backup-manual').style.display = 'none';
            document.getElementById('fl-backup-path').textContent = folder.split(/[\\/]/).pop();
          }
        }).catch(function(e) { console.error('[choose-folder]', e); });
      }
    });

    /* Step 2 -> Step 3 */
    document.getElementById('fl-next-2')?.addEventListener('click', function() { showStep(3); });

    /* Step 3: Done */
    document.getElementById('fl-save')?.addEventListener('click', function() {
      modal.style.display = 'none';
      var name = _flSettings.feeEarnerNameDefault || '';
      showToast('Welcome to Custody Note' + (name ? ', ' + name : '') + '!', 'success', 4000);
    });

    /* Skip (from step 1) */
    document.getElementById('fl-skip')?.addEventListener('click', function() {
      modal.style.display = 'none';
      var banner = document.createElement('div');
      banner.className = 'setup-warning-banner';
      banner.textContent = 'Setup incomplete \u2014 click here to add your name and DSCC PIN (required for billing)';
      banner.addEventListener('click', function() {
        showView('settings');
        banner.remove();
      });
      document.querySelector('.app-header')?.insertAdjacentElement('afterend', banner);
    });
  }

/* ── Session lock / idle timeout ── */
(function() {
  var _idleTimer = null;
  var _locked = false;
  var _unlockBusy = false;

  function _setLockError(msg) {
    var errorEl = document.getElementById('session-lock-error');
    if (errorEl) errorEl.textContent = msg || '';
  }

  function _getLockPasswordInput() {
    return document.getElementById('session-lock-password');
  }

  function _updateLockHint() {
    var hintEl = document.getElementById('session-lock-hint');
    if (!hintEl || !window.api || !window.api.sessionLockStatus) return;
    window.api.sessionLockStatus().then(function(status) {
      if (!status || !status.canLock) {
        hintEl.textContent = 'Session locking needs a recovery password or admin password set in Settings.';
        return;
      }
      hintEl.textContent = 'Enter your ' + (status.label || 'password') + ' to continue.';
    }).catch(function() {
      hintEl.textContent = 'Enter your password to continue.';
    });
  }

  function _lock() {
    if (_locked) return;
    if (!window.api || !window.api.sessionLockStatus) return;
    window.api.sessionLockStatus().then(function(status) {
      if (!status || !status.canLock) {
        showToast('Session lock requires a password. Set one in Settings > Security.', 'warning', 5000);
        _resetIdleTimer();
        return;
      }
      _locked = true;
      var overlay = document.getElementById('session-lock-overlay');
      if (overlay) overlay.style.display = 'flex';
      var passwordInput = _getLockPasswordInput();
      if (passwordInput) passwordInput.value = '';
      _setLockError('');
      _updateLockHint();
      if (passwordInput) passwordInput.focus();
    }).catch(function() {
      _resetIdleTimer();
    });
  }

  function _unlock() {
    if (_unlockBusy || !window.api || !window.api.sessionUnlock) return;
    var passwordInput = _getLockPasswordInput();
    var password = passwordInput ? passwordInput.value : '';
    _unlockBusy = true;
    _setLockError('');
    window.api.sessionUnlock(password).then(function(result) {
      if (!result || !result.ok) {
        _setLockError(result && result.error ? result.error : 'Unlock failed.');
        if (passwordInput) passwordInput.focus();
        return;
      }
      _locked = false;
      var overlay = document.getElementById('session-lock-overlay');
      if (overlay) overlay.style.display = 'none';
      if (passwordInput) passwordInput.value = '';
      _resetIdleTimer();
    }).catch(function(err) {
      _setLockError(err && err.message ? err.message : 'Unlock failed.');
    }).finally(function() {
      _unlockBusy = false;
    });
  }

  // Security default: when no value is configured, fall back to a 10-minute
  // idle lock for legal-sector use. The user can disable in Settings (set 0)
  // but the default-on stance protects unattended laptops in chambers, on
  // trains, etc. Existing installs that explicitly chose 0 still get 0.
  var _IDLE_DEFAULT_MINUTES = 10;
  function _getIdleMinutes() {
    var s = window._appSettingsCache || {};
    var raw = s.idleTimeoutMinutes;
    if (raw === undefined || raw === null || raw === '') return _IDLE_DEFAULT_MINUTES;
    var n = parseInt(raw, 10);
    if (isNaN(n)) return _IDLE_DEFAULT_MINUTES;
    return n;
  }
  function _resetIdleTimer() {
    if (_idleTimer) clearTimeout(_idleTimer);
    var mins = _getIdleMinutes();
    if (!mins || mins <= 0) return;
    _idleTimer = setTimeout(_lock, mins * 60 * 1000);
  }
  window._resetIdleTimer = _resetIdleTimer;

  // Subscribe to OS-driven force-lock events: when the user locks Windows,
  // the laptop suspends, or the system shuts down, we lock immediately
  // regardless of the configured idle timeout.
  if (window.api && typeof window.api.onSessionForceLock === 'function') {
    try {
      window.api.onSessionForceLock(function(meta) {
        try {
          if (window.api && window.api.sessionLockStatus) {
            // Even if no recovery/admin password is configured, ensure the
            // app is at least visually obscured so a passer-by sees nothing.
            window.api.sessionLockStatus().then(function(status) {
              if (status && status.canLock) {
                _lock();
              } else {
                // Best-effort visual blanker: hide the main UI and show a
                // simple "Session locked" overlay even without a credential.
                _showCredentialFreeBlanker(meta && meta.reason);
              }
            }).catch(function() {
              _showCredentialFreeBlanker(meta && meta.reason);
            });
          }
        } catch (_) {}
      });
    } catch (_) {}
  }

  function _showCredentialFreeBlanker(reason) {
    try {
      var existing = document.getElementById('cn-credentialfree-blanker');
      if (existing) return;
      var div = document.createElement('div');
      div.id = 'cn-credentialfree-blanker';
      div.setAttribute('role', 'alertdialog');
      div.setAttribute('aria-modal', 'true');
      div.style.cssText =
        'position:fixed;inset:0;z-index:2147483647;background:#0f172a;color:#f8fafc;'
        + 'display:flex;align-items:center;justify-content:center;flex-direction:column;'
        + 'font-family:Segoe UI,Arial,sans-serif;padding:2rem;text-align:center;';
      div.innerHTML =
        '<h2 style="margin:0 0 1rem;font-size:1.5rem;">Session locked</h2>'
        + '<p style="max-width:36rem;line-height:1.5;">'
        + 'CustodyNote was locked because the operating system reported a '
        + (reason ? '<code>' + reason.replace(/[<>&]/g, '') + '</code>' : 'lock event')
        + '. To unlock, set a recovery password or admin password in Settings &gt; Security '
        + 'and re-open the app.</p>'
        + '<button type="button" id="cn-credentialfree-dismiss" '
        + 'style="margin-top:1.5rem;padding:0.5rem 1.25rem;border:1px solid #475569;'
        + 'background:#1e293b;color:#f8fafc;border-radius:6px;cursor:pointer;">'
        + 'Dismiss (no real client data)</button>';
      document.body.appendChild(div);
      var btn = document.getElementById('cn-credentialfree-dismiss');
      if (btn) btn.addEventListener('click', function() {
        try { div.parentNode.removeChild(div); } catch (_) {}
      });
    } catch (_) {}
  }

  ['mousemove', 'mousedown', 'keydown', 'touchstart', 'scroll'].forEach(function(ev) {
    document.addEventListener(ev, function() {
      if (!_locked) _resetIdleTimer();
    }, { passive: true });
  });

  document.addEventListener('DOMContentLoaded', function() {
    var unlockBtn = document.getElementById('session-lock-unlock-btn');
    if (unlockBtn) unlockBtn.addEventListener('click', _unlock);
    var toggleBtn = document.getElementById('session-lock-toggle');
    var passwordInput = _getLockPasswordInput();
    if (toggleBtn && passwordInput) {
      toggleBtn.addEventListener('click', function() {
        var isPassword = passwordInput.type === 'password';
        passwordInput.type = isPassword ? 'text' : 'password';
        toggleBtn.textContent = isPassword ? 'Hide' : 'Show';
        toggleBtn.setAttribute('aria-label', isPassword ? 'Hide password' : 'Show password');
      });
    }
    document.addEventListener('keydown', function(e) {
      if (_locked && e.key === 'Enter') _unlock();
    });

    /* Magic-link session unlock */
    var _magicPollTimer = null;
    var forgotLink = document.getElementById('session-lock-forgot');
    var magicFlow = document.getElementById('session-lock-magic-flow');
    var magicStatus = document.getElementById('session-lock-magic-status');
    var magicCancel = document.getElementById('session-lock-magic-cancel');

    if (forgotLink) {
      forgotLink.addEventListener('click', function(e) {
        e.preventDefault();
        if (!window.api || !window.api.authMagicLink) {
          _setLockError('Email unlock is not available. Contact support.');
          return;
        }
        var email = (window._appSettingsCache && window._appSettingsCache.email) || '';
        if (!email && window.api.authStatus) {
          window.api.authStatus().then(function(st) {
            if (st && st.email) {
              _startMagicUnlock(st.email);
            } else {
              _setLockError('No email on file. Contact support or restart the app.');
            }
          }).catch(function() {
            _setLockError('Could not retrieve email. Contact support.');
          });
        } else if (email) {
          _startMagicUnlock(email);
        } else {
          _setLockError('No email on file. Contact support or restart the app.');
        }
      });
    }

    function _startMagicUnlock(email) {
      _setLockError('');
      if (magicFlow) magicFlow.style.display = '';
      if (magicStatus) magicStatus.textContent = 'Sending unlock link to ' + email + '\u2026';
      document.getElementById('session-lock-magic')?.style && (document.getElementById('session-lock-magic').style.display = 'none');

      window.api.authMagicLink({ email: email }).then(function(resp) {
        if (!resp || !resp.ok) {
          if (magicStatus) magicStatus.textContent = resp && resp.error ? resp.error : 'Failed to send unlock link.';
          return;
        }
        if (magicStatus) magicStatus.textContent = 'Check your email and click the link to unlock.';
        var pollId = resp.pollId;
        var _pollAttempts = 0;
        var _pollMaxAttempts = 100;
        _magicPollTimer = setInterval(function() {
          _pollAttempts++;
          if (_pollAttempts > _pollMaxAttempts) {
            clearInterval(_magicPollTimer);
            _magicPollTimer = null;
            if (magicStatus) magicStatus.textContent = 'Unlock timed out. Try again.';
            return;
          }
          window.api.authPoll({ pollId: pollId }).then(function(pr) {
            if (pr && pr.ok) {
              clearInterval(_magicPollTimer);
              _magicPollTimer = null;
              _locked = false;
              var overlay = document.getElementById('session-lock-overlay');
              if (overlay) overlay.style.display = 'none';
              if (magicFlow) magicFlow.style.display = 'none';
              document.getElementById('session-lock-magic')?.style && (document.getElementById('session-lock-magic').style.display = '');
              _resetIdleTimer();
              showToast('Session unlocked via email', 'success');
            } else if (pr && pr.expired) {
              clearInterval(_magicPollTimer);
              _magicPollTimer = null;
              if (magicStatus) magicStatus.textContent = 'Link expired. Try again.';
            }
          }).catch(function(e) { console.error('[magic-poll-unlock]', e); });
        }, 3000);
      }).catch(function() {
        if (magicStatus) magicStatus.textContent = 'Failed to send unlock link. Try again later.';
      });
    }

    if (magicCancel) {
      magicCancel.addEventListener('click', function() {
        if (_magicPollTimer) { clearInterval(_magicPollTimer); _magicPollTimer = null; }
        if (magicFlow) magicFlow.style.display = 'none';
        document.getElementById('session-lock-magic')?.style && (document.getElementById('session-lock-magic').style.display = '');
      });
    }
  });
})();

function _showPinTipIfNeeded() {
  /* Only show on Windows (Electron exposes process.platform via navigator.userAgent or window.api) */
  if (!navigator.userAgent.includes('Windows') && !navigator.platform.includes('Win')) return;
  try {
    if (localStorage.getItem('cn-pin-tip-dismissed')) return;
  } catch (_) { return; }
  setTimeout(function() {
    var banner = document.createElement('div');
    banner.className = 'setup-warning-banner pin-tip-banner';
    banner.innerHTML = 'Tip: right-click <strong>Custody Note</strong> in the Start Menu or Taskbar and choose <strong>Pin to taskbar</strong> for quick access. <span class="pin-tip-dismiss" title="Dismiss">&times;</span>';
    banner.querySelector('.pin-tip-dismiss').addEventListener('click', function(e) {
      e.stopPropagation();
      banner.remove();
      try { localStorage.setItem('cn-pin-tip-dismissed', '1'); } catch (_) {}
    });
    document.querySelector('.app-header')?.insertAdjacentElement('afterend', banner);
  }, 2000);
}

function _initCloseGuard() {
  if (!window.api || !window.api.onCheckUnsavedChanges) return;
  window.api.onCheckUnsavedChanges(function() {
    var formActive = document.getElementById('view-form')?.classList.contains('active');
    var isDirty = formActive && currentRecordStatus === 'draft' && (_draftSaveInFlight || _draftSaveQueued || _quietSaveDebounceTimer);
    if (isDirty) {
      showConfirm('You have unsaved changes. Close anyway?', 'Unsaved Changes').then(function(ok) {
        if (ok) window.api.confirmClose();
      });
    } else {
      window.api.confirmClose();
    }
  });
}

function safeInit() {
  try {
    init();
    if (window.OfficerEmailsPanel && typeof window.OfficerEmailsPanel.init === 'function') {
      try { window.OfficerEmailsPanel.init(); } catch (e) { console.error('[OfficerEmailsPanel.init]', e); }
    }
    if (window.OfficerEmailsStandalone && typeof window.OfficerEmailsStandalone.init === 'function') {
      try { window.OfficerEmailsStandalone.init(); } catch (e) { console.error('[OfficerEmailsStandalone.init]', e); }
    }
    _showPinTipIfNeeded();
    _initCloseGuard();
  } catch (err) {
    console.error('[init] FATAL ERROR in init():', err);
  }
}
function gatedInit() {
  if (typeof window.onLicenceReady === 'function') {
    window.onLicenceReady(safeInit);
  } else {
    safeInit();
  }
}
if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', gatedInit);
else gatedInit();
